def draw_square(width, height):
    """Draws a square with the given width and height."""
    return [True] * (width * height)

def draw_circle(width, height):
    """Draws a circle with the given width and height."""
    # Convert string inputs to integers
    width = int(width)
    height = int(height)

    # Create a list to represent the circle
    circle = []
    for y in range(height):
        for x in range(width):
            # Check if the point is within the circle
            if (x - width / 2) ** 2 + (y - height / 2) ** 2 <= (min(width, height) / 2) ** 2:
                circle.append(True)
            else:
                circle.append(False)
    return circle
